import { useEffect, useMemo, useState } from "react";

import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation } from "@tanstack/react-query";
import { CheckCircle2, Copy, UserPlus } from "lucide-react";
import { useForm, useWatch } from "react-hook-form";
import { Link, useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { z } from "zod";

import { AuthLayout } from "@/components/layout/AuthLayout";
import { Button } from "@/components/ui/Button";
import { Card } from "@/components/ui/Card";
import { authService } from "@/services/endpoints/auth";
import { cn } from "@/utils/cn";

const registerSchema = z.object({
  billingId: z.string().trim().min(4, "Введите лицевой счёт"),
  phone: z.string().trim().min(5, "Введите телефон"),
  email: z.string().trim().email("Введите корректный email").or(z.literal("")),
  firstName: z.string().trim().min(2, "Введите имя"),
  lastName: z.string().trim().min(2, "Введите фамилию"),
  smsCode: z.string().optional(),
  password: z.string().optional(),
});

type RegisterValues = z.infer<typeof registerSchema>;

function getErrorMessage(error: unknown) {
  if (
    error &&
    typeof error === "object" &&
    "response" in error &&
    error.response &&
    typeof error.response === "object" &&
    "data" in error.response &&
    error.response.data &&
    typeof error.response.data === "object" &&
    "detail" in error.response.data
  ) {
    return String(error.response.data.detail);
  }

  if (error instanceof Error) {
    return error.message;
  }

  return "Не удалось продолжить регистрацию. Попробуйте ещё раз.";
}

function RegisterPage() {
  const navigate = useNavigate();
  const [phase, setPhase] = useState<"request" | "confirm">("request");
  const [demoCode, setDemoCode] = useState<string | null>(null);
  const [cooldown, setCooldown] = useState(0);

  const form = useForm<RegisterValues>({
    resolver: zodResolver(registerSchema),
    defaultValues: {
      billingId: "",
      phone: "",
      email: "",
      firstName: "",
      lastName: "",
      smsCode: "",
      password: "",
    },
  });

  const phoneValue = useWatch({ control: form.control, name: "phone" }) ?? "";
  const passwordValue = useWatch({ control: form.control, name: "password" }) ?? "";
  const smsCodeValue = useWatch({ control: form.control, name: "smsCode" }) ?? "";

  useEffect(() => {
    if (!cooldown) {
      return;
    }

    const timer = window.setTimeout(() => setCooldown((current) => Math.max(current - 1, 0)), 1000);
    return () => window.clearTimeout(timer);
  }, [cooldown]);

  const passwordHint = useMemo(() => {
    if (!passwordValue?.trim()) {
      return "Пароль необязателен. Можно завершить регистрацию и входить по SMS.";
    }

    if (passwordValue.length < 8) {
      return "Добавьте минимум 8 символов.";
    }

    return "Пароль задан. Его можно будет использовать вместе с SMS или для staff-like сценариев.";
  }, [passwordValue]);

  const requestMutation = useMutation({
    mutationFn: (values: RegisterValues) =>
      authService.register({
        billing_id: values.billingId.trim().toUpperCase(),
        phone: values.phone.trim(),
        email: values.email.trim() || undefined,
        first_name: values.firstName.trim(),
        last_name: values.lastName.trim(),
      }),
    onSuccess: (result) => {
      setPhase("confirm");
      setDemoCode(result.demo_sms_code ?? null);
      setCooldown(result.demo_sms_ttl ? Math.min(result.demo_sms_ttl, 60) : 60);
      toast.success(result.message);
      form.setFocus("smsCode");
    },
    onError: (error) => {
      toast.error(getErrorMessage(error));
    },
  });

  const confirmMutation = useMutation({
    mutationFn: (values: RegisterValues) =>
      authService.confirmRegister({
        phone: values.phone.trim(),
        sms_code: values.smsCode?.trim() || "",
        password: values.password?.trim() || undefined,
      }),
    onSuccess: (result) => {
      toast.success(result.message || "Регистрация завершена.");
      navigate("/login", { replace: true });
    },
    onError: (error) => {
      toast.error(getErrorMessage(error));
    },
  });

  const handleCopyDemoCode = async () => {
    if (!demoCode) {
      return;
    }

    try {
      await navigator.clipboard.writeText(demoCode);
      form.setValue("smsCode", demoCode);
      toast.success("Код скопирован и подставлен в форму.");
    } catch {
      form.setValue("smsCode", demoCode);
      toast.success("Код подставлен в форму.");
    }
  };

  const submit = form.handleSubmit((values) => {
    if (phase === "request") {
      requestMutation.mutate(values);
      return;
    }

    if (!values.smsCode?.trim()) {
      form.setError("smsCode", { type: "manual", message: "Введите код из SMS" });
      return;
    }

    confirmMutation.mutate(values);
  });

  return (
    <AuthLayout>
      <Card className="auth-form-card stack-lg">
        <div className="auth-form-head">
          <div>
            <p className="section-eyebrow">Register</p>
            <h2 className="auth-form-title">Подключение нового аккаунта MTN</h2>
            <p className="auth-form-copy">
              Проверяем лицевой счёт, подтверждаем номер по SMS и при желании сразу задаём
              пароль для будущего быстрого входа.
            </p>
          </div>
          <div className="auth-head-badge">
            <UserPlus size={16} />
            <span>3 шага до кабинета</span>
          </div>
        </div>

        <div className="auth-stepper">
          {[
            { id: 1, title: "Проверка договора", description: "Лицевой счёт и контакты" },
            { id: 2, title: "Подтверждение номера", description: "Код из SMS" },
            { id: 3, title: "Финиш", description: "Активация аккаунта" },
          ].map((step) => (
            <div
              key={step.id}
              className={cn(
                "auth-step-card",
                (phase === "request" ? 1 : 2) === step.id && "is-active",
                phase === "confirm" && step.id === 1 && "is-complete",
                phase === "confirm" && step.id === 2 && smsCodeValue && "is-active",
              )}
            >
              <div className="auth-step-index">0{step.id}</div>
              <div>
                <strong>{step.title}</strong>
                <p>{step.description}</p>
              </div>
            </div>
          ))}
        </div>

        <form className="stack-md" onSubmit={submit}>
          {phase === "request" ? (
            <>
              <div className="form-grid">
                <div className="field">
                  <label htmlFor="billingId">Лицевой счёт</label>
                  <input id="billingId" placeholder="Например, MTN-204501" {...form.register("billingId")} />
                  <span className="muted">
                    {form.formState.errors.billingId?.message ??
                      "Счёт сверяется с биллингом MTN перед созданием аккаунта."}
                  </span>
                </div>
                <div className="field">
                  <label htmlFor="phone">Телефон</label>
                  <input id="phone" placeholder="+7 (999) 123-45-67" autoComplete="tel" {...form.register("phone")} />
                  <span className="muted">{form.formState.errors.phone?.message}</span>
                </div>
                <div className="field">
                  <label htmlFor="email">Email</label>
                  <input id="email" placeholder="you@mtn.ru" autoComplete="email" {...form.register("email")} />
                  <span className="muted">
                    {form.formState.errors.email?.message ?? "На этот адрес будут приходить квитанции и сервисные письма."}
                  </span>
                </div>
                <div className="field">
                  <label htmlFor="firstName">Имя</label>
                  <input id="firstName" placeholder="Алексей" {...form.register("firstName")} />
                  <span className="muted">{form.formState.errors.firstName?.message}</span>
                </div>
                <div className="field">
                  <label htmlFor="lastName">Фамилия</label>
                  <input id="lastName" placeholder="Иванов" {...form.register("lastName")} />
                  <span className="muted">{form.formState.errors.lastName?.message}</span>
                </div>
              </div>

              <Card className="auth-inline-card stack-sm">
                <div className="inline-actions">
                  <CheckCircle2 size={18} />
                  <strong>Что произойдёт дальше</strong>
                </div>
                <p className="muted">
                  После проверки биллинга MTN отправит SMS-код на номер договора.
                  Аккаунт активируется только после подтверждения номера.
                </p>
              </Card>
            </>
          ) : (
            <>
              <Card className="auth-inline-card stack-sm">
                <div className="toolbar-row">
                  <div>
                    <strong>Подтвердите регистрацию</strong>
                    <p className="muted">
                      Код отправлен на {phoneValue}. После подтверждения аккаунт станет активным.
                    </p>
                  </div>
                  {demoCode ? (
                    <Button type="button" variant="secondary" size="sm" onClick={handleCopyDemoCode}>
                      <Copy size={14} />
                      Скопировать код
                    </Button>
                  ) : null}
                </div>
                <div className="inline-actions">
                  <Button
                    type="button"
                    variant="secondary"
                    size="sm"
                    disabled={cooldown > 0 || requestMutation.isPending}
                    onClick={() => requestMutation.mutate(form.getValues())}
                  >
                    {requestMutation.isPending ? "Отправляем..." : "Отправить код повторно"}
                  </Button>
                  <span className="muted">
                    {demoCode ? `Демо-код: ${demoCode}` : cooldown > 0 ? `Новый код через ${cooldown} сек.` : "Можно запросить новый код"}
                  </span>
                </div>
              </Card>

              <div className="form-grid">
                <div className="field">
                  <label htmlFor="smsCode">SMS-код</label>
                  <input id="smsCode" inputMode="numeric" autoComplete="one-time-code" placeholder="6 цифр" {...form.register("smsCode")} />
                  <span className="muted">
                    {form.formState.errors.smsCode?.message ?? "Введите код, который пришёл на номер договора."}
                  </span>
                </div>
                <div className="field">
                  <label htmlFor="password">Пароль</label>
                  <input id="password" type="password" autoComplete="new-password" placeholder="Необязательно" {...form.register("password")} />
                  <span className="muted">{passwordHint}</span>
                </div>
              </div>
            </>
          )}

          <div className="inline-actions">
            <Button type="submit" disabled={requestMutation.isPending || confirmMutation.isPending}>
              {requestMutation.isPending || confirmMutation.isPending
                ? "Обрабатываем..."
                : phase === "request"
                  ? "Проверить счёт и отправить код"
                  : "Завершить регистрацию"}
            </Button>
            {phase === "confirm" ? (
              <Button type="button" variant="secondary" onClick={() => setPhase("request")}>
                Вернуться к данным
              </Button>
            ) : null}
          </div>
        </form>

        <div className="auth-links-grid">
          <Link className="link-line" to="/login">
            Уже есть аккаунт? Войти
          </Link>
          <Link className="link-line" to="/recover">
            Нужно восстановить пароль?
          </Link>
        </div>
      </Card>
    </AuthLayout>
  );
}

export default RegisterPage;
